   235→    if (this.ws && this.watchedCwd !== cwd) {
   236→      this.ws.close()
   237→      this.ws = null
   238→    }
   239→    this.watching = true
   240→    this.watchedCwd = cwd
   241→    this.reconnectDelay = 1000
   242→    this.connectWs(cwd)
   243→  }
   244→
   245→  private connectWs(cwd: string): void {
   246→    if (this.ws) return
   247→    try {
   248→      this.ws = new WebSocket(`ws://localhost:${DAEMON_PORT}/ws?project=${encodeURIComponent(cwd)}`)
   249→      this.ws.onmessage = (event) => {
   250→        try {
   251→          const msg = JSON.parse(event.data)
   252→          if (msg.event === 'tasks:updates' || msg.event === 'task_updated') {
   253→            this.wsCallbacks.forEach(cb => cb({ cwd }))
   254→          }
   255→        } catch { /* ignore parse errors */ }
   256→      }
   257→      this.ws.onopen = () => {
   258→        this.reconnectDelay = 1000 // Reset backoff on successful connection
   259→      }
   260→      this.ws.onclose = () => {
   261→        this.ws = null
   262→        // Auto-reconnect with exponential backoff (cap at 30s)
   263→        if (this.watching && this.watchedCwd === cwd) {
   264→          this.reconnectTimer = setTimeout(() => this.connectWs(cwd), this.reconnectDelay)
   265→          this.reconnectDelay = Math.min(this.reconnectDelay * 2, 30000)
   266→        }
   267→      }
   268→      this.ws.onerror = () => {
   269→        // onclose will fire after onerror, triggering reconnect
   270→      }
   271→    } catch { /* daemon not running — reconnect will retry */ }
   272→  }
   273→
   274→  unwatch(_cwd: string): void {
   275→    this.watching = false
   276→    this.watchedCwd = null
   277→    if (this.reconnectTimer) {
   278→      clearTimeout(this.reconnectTimer)
   279→      this.reconnectTimer = null
   280→    }
   281→    this.ws?.close()
   282→    this.ws = null
   283→  }
   284→
   285→  onTasksChanged(callback: (data: { cwd: string }) => void): () => void {
   286→    this.wsCallbacks.add(callback)
   287→    return () => { this.wsCallbacks.delete(callback) }
   288→  }
   289→}
   290→
